const WINE_IDX = {};
for (const entry of WINE_DATA) {
  WINE_IDX[entry[0]] = { tipo: WINE_TIPI[entry[1]], regione: WINE_REGIONI[entry[2]] };
}

export function lookupWine(nome) {
  if (!nome || nome.length < 3) return null;
  const n = nome.toLowerCase()
    .normalize("NFD").replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-z0-9\s]/g, " ").replace(/\s+/g, " ").trim();
  if (WINE_IDX[n]) return WINE_IDX[n];
  const keys = Object.keys(WINE_IDX).sort((a, b) => b.length - a.length);
  for (const k of keys) {
    if (n.includes(k) && k.length >= 4) return WINE_IDX[k];
  }
  return null;
}
